        mock_coll = Mock()
        mock_coll.get.side_effect = TimeoutException("1ms timeout")
        mock_coll.get_any_replica.return_value = self.mock_result

        result = None
        try:
            mock_coll.get("test_key", timeout=timedelta(milliseconds=1))
        except TimeoutException:
